/// <summary>
/// This an UIBuilder class for report ZeroRatesSalesReport
/// </summary>
internal final class ETGZeroRatedSalesReportUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGZeroRatedSalesReportContract contract;
    DialogField                     dialogFromDate;
    DialogField                     dialogToDate;
    DialogField                     custAccount;
    DialogField                     etgBussinessSegment;
    DialogField                     etgConnectionType;
    DialogField                     invoiceId;
}

Method.Source:
public void build()
{
    contract            = this.dataContractObject() as ETGZeroRatedSalesReportContract;
    dialogFromDate      = this.addDialogField(methodStr(ETGZeroRatedSalesReportContract, parmFromDate), contract);
    dialogToDate        = this.addDialogField(methodStr(ETGZeroRatedSalesReportContract, parmToDate), contract);
    custAccount         = this.addDialogField(methodStr(ETGZeroRatedSalesReportContract, parmCustAccount), contract);
    etgBussinessSegment = this.addDialogField(methodStr(ETGZeroRatedSalesReportContract, parmBusinessSegment), contract);
    etgConnectionType   = this.addDialogField(methodStr(ETGZeroRatedSalesReportContract, parmConnectionType), contract);
    invoiceId           = this.addDialogField(methodStr(ETGZeroRatedSalesReportContract, parmInvoiceId), contract);
}

public void postBuild()
{
    Dialog dialogobj = this.dialog();
    super();

    dialogFromDate      = this.bindInfo().getDialogField(contract, methodStr(ETGZeroRatedSalesReportContract, parmFromDate));
    dialogToDate        = this.bindInfo().getDialogField(contract, methodStr(ETGZeroRatedSalesReportContract, parmToDate));
    etgBussinessSegment = this.bindInfo().getDialogField(contract, methodStr(ETGZeroRatedSalesReportContract, parmBusinessSegment));
    etgConnectionType   = this.bindInfo().getDialogField(contract, methodStr(ETGZeroRatedSalesReportContract, parmConnectionType));
    invoiceId           = this.bindInfo().getDialogField(contract, methodStr(ETGZeroRatedSalesReportContract, parmInvoiceId));
    invoiceId.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGZeroRatedSalesReportUIBuilder, InvoiceIdMultiSelectLookup), this);
    custAccount         = this.bindInfo().getDialogField(contract, methodStr(ETGZeroRatedSalesReportContract, parmCustAccount));
    custAccount.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGZeroRatedSalesReportUIBuilder, custAccountMultiSelectLookup), this);
    if(custAccount)
    {
        custAccount.lookupButton(2);
    }
    if(invoiceId)
    {
        invoiceId.lookupButton(2);
    }
}

public void postRun()
{
    ETGZeroRatedSalesReportContract etgZeroRatedSalesReportContract = this.dataContractObject();
}

/// <summary>
/// Multiselect lookup for cust account parameter
/// </summary>
/// <param name = "_control">FormStringControl</param>
public void custAccountMultiSelectLookup(FormStringControl _control)
{
    Query                 query = new Query();
    QueryBuildDataSource  qbds;
    container             conCustTable;

    qbds = query.addDataSource(tableNum(CustTable));

    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(CustTable,AccountNum));

    qbds = qbds.addDataSource(tableNum(DirPartyTable));
    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(DirPartyTable,Name));
    qbds.relations(true);
    SysLookUpMultiSelectGrid::lookup(query, _control, _control, _control,conCustTable);
}

/// <summary>
/// Multi select lookup for InvoiceId parameter
/// </summary>
/// <param name = "_control">FormStringControl</param>
public void InvoiceIdMultiSelectLookup(FormStringControl _control)
{
    Query  query = new Query();
    QueryBuildDataSource qbds;
    container conInvoiceId;
    qbds = query.addDataSource(tableNum(CustInvoiceJour));
    qbds.addSelectionField(fieldNum(CustInvoiceJour, InvoiceId));
    qbds.addSelectionField(fieldNum(CustInvoiceJour, SalesId));
    qbds.addSelectionField(fieldNum(CustInvoiceJour, InvoiceAccount));
    SysLookUpMultiSelectGrid::lookup(query, _control, _control, _control,conInvoiceId);
}
